INSERT INTO citation (jour_ramadan, source, text, type) VALUES
                                                            (1,  'Quran 2:185',     'شَهْرُ رَمَضَانَ الَّذِي أُنزِلَ فِيهِ الْقُرْآنُ هُدًى لِّلنَّاسِ', 'QURAN'),
                                                            (2,  'Bukhari 1904',    'مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ', 'HADITH'),
                                                            (3,  'Quran 2:186',     'وَإِذَا سَأَلَكَ عِبَادِي عَنِّي فَإِنِّي قَرِيبٌ', 'QURAN'),
                                                            (4,  'Muslim 1151',     'الصِّيَامُ جُنَّةٌ فَلَا يَرْفُثْ وَلَا يَجْهَلْ', 'HADITH'),
                                                            (5,  'Quran 97:1',      'إِنَّا أَنزَلْنَاهُ فِي لَيْلَةِ الْقَدْرِ', 'QURAN'),
                                                            (6,  'Tirmidhi 3549',   'اللَّهُمَّ إِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّي', 'HADITH'),
                                                            (7,  'Quran 3:133',     'وَسَارِعُوا إِلَىٰ مَغْفِرَةٍ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا السَّمَاوَاتُ وَالْأَرْضُ', 'QURAN'),
                                                            (8,  'Bukhari 1902',    'إِذَا جَاءَ رَمَضَانُ فُتِّحَتْ أَبْوَابُ الْجَنَّةِ', 'HADITH'),
                                                            (9,  'Quran 2:153',     'يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَعِينُوا بِالصَّبْرِ وَالصَّلَاةِ', 'QURAN'),
                                                            (10, 'Muslim 1163',     'تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً', 'HADITH'),
                                                            (11, 'Quran 73:20',     'وَأَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ', 'QURAN'),
                                                            (12, 'Bukhari 6407',    'أَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ صَلَاةُ اللَّيْلِ', 'HADITH'),
                                                            (13, 'Quran 17:79',     'وَمِنَ اللَّيْلِ فَتَهَجَّدْ بِهِ نَافِلَةً لَّكَ', 'QURAN'),
                                                            (14, 'Muslim 223',      'الطَّهُورُ شَطْرُ الْإِيمَانِ', 'HADITH'),
                                                            (15, 'Quran 13:28',     'أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ', 'QURAN'),
                                                            (16, 'Bukhari 6491',    'نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنَ النَّاسِ الصِّحَّةُ وَالْفَرَاغُ', 'HADITH'),
                                                            (17, 'Quran 3:200',     'يَا أَيُّهَا الَّذِينَ آمَنُوا اصْبِرُوا وَصَابِرُوا وَرَابِطُوا', 'QURAN'),
                                                            (18, 'Muslim 2699',     'مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِ', 'HADITH'),
                                                            (19, 'Quran 39:53',     'قُلْ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَىٰ أَنفُسِهِمْ لَا تَقْنَطُوا مِن رَّحْمَةِ اللَّهِ', 'QURAN'),
                                                            (20, 'Bukhari 6018',    'الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ', 'HADITH'),
                                                            (21, 'Quran 16:97',     'مَنْ عَمِلَ صَالِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً', 'QURAN'),
                                                            (22, 'Tirmidhi 2318',   'اغْتَنِمْ خَمْسًا قَبْلَ خَمْسٍ شَبَابَكَ قَبْلَ هَرَمِكَ', 'HADITH'),
                                                            (23, 'Quran 2:286',     'لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا', 'QURAN'),
                                                            (24, 'Muslim 2564',     'لَا تَحْقِرَنَّ مِنَ الْمَعْرُوفِ شَيْئًا', 'HADITH'),
                                                            (25, 'Quran 94:5',      'فَإِنَّ مَعَ الْعُسْرِ يُسْرًا', 'QURAN'),
                                                            (26, 'Bukhari 52',      'الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ', 'HADITH'),
                                                            (27, 'Quran 49:13',     'إِنَّ أَكْرَمَكُمْ عِندَ اللَّهِ أَتْقَاكُمْ', 'QURAN'),
                                                            (28, 'Muslim 2553',     'الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَٰنُ', 'HADITH'),
                                                            (29, 'Quran 55:60',     'هَلْ جَزَاءُ الْإِحْسَانِ إِلَّا الْإِحْسَانُ', 'QURAN'),
                                                            (30, 'Bukhari 6463',    'خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ', 'HADITH');
