INSERT INTO conseils (categorie, contenu, genre, titre, pour_ramadan) VALUES
    ('NUTRITION',   'Commencez votre suhoor avec des dattes et de l eau pour une énergie durable tout au long de la journée de jeûne.', 'TOUS',  'Suhoor idéal', true),
    ('NUTRITION',   'Rompez votre jeûne avec des dattes et de l eau, puis prenez un repas léger avant la prière du Maghrib.', 'TOUS',  'Iftar sain', true),
    ('NUTRITION',   'Évitez les aliments trop salés et trop sucrés pour maintenir une bonne hydratation.', 'TOUS',  'Alimentation équilibrée', false),
    ('SPIRITUEL',   'Consacrez au moins 30 minutes par jour à la lecture du Coran.', 'TOUS',  'Khatm Al Quran', false),
    ('SPIRITUEL',   'Profitez des dernières 10 nuits du Ramadan pour intensifier vos adorations et rechercher Laylat Al Qadr.', 'TOUS',  'Les 10 dernières nuits', true),
    ('SPIRITUEL',   'Faites du dhikr après chaque prière pour maintenir votre cœur connecté à Allah.', 'TOUS',  'Dhikr quotidien', false),
    ('SPORT',       'Pratiquez une activité physique légère 2 heures après l iftar pour maintenir votre forme.', 'TOUS',  'Sport après l iftar', true),
    ('SPORT',       'La marche de 30 minutes au quotidien est excellente pour la santé.', 'TOUS',  'Marche saine', false),
    ('SOMMEIL',     'Essayez de dormir tôt après Tarawih pour vous réveiller facilement pour le Suhoor.', 'TOUS',  'Gestion du sommeil (Ramadan)', true),
    ('SOMMEIL',     'Une sieste courte de 20 minutes après Dhuhr peut vous aider à maintenir votre énergie.', 'TOUS',  'La sieste', false),
    ('MOTIVATION',  'Rappelez vous que chaque difficulté du jeûne est récompensée par Allah.', 'TOUS',  'La patience du jeûneur', true),
    ('MOTIVATION',  'Fixez vous des objectifs spirituels clairs pour avancer vers Allah.', 'TOUS',  'Objectifs spirituels', false),
    ('REGLES',      'Pendant les règles, compensez l absence de prière par beaucoup de dhikr, de lecture et de dua.', 'Femme', 'Adoration pendant les règles', false),
    ('REGLES',      'Les jours de jeûne manqués pendant le Ramadan doivent être compensés après la fête.', 'Femme', 'Compensation du jeûne', true),
    ('NUTRITION',   'Les femmes enceintes ou allaitantes peuvent être dispensées du jeûne. Consultez un médecin.', 'Femme', 'Jeûne et maternité', true),
    ('SPORT',       'Maintenez une activité physique pour garder votre énergie tout au long de la semaine.', 'Homme', 'Sport et muscles', false),
    ('SPIRITUEL',   'La prière en congrégation à la mosquée multiplie les récompenses par 27.', 'Homme', 'Prière en congrégation', false);
